package dbutil

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"testing"
)

// --- Unit tests (no DB) ---

func TestMergeJSONB(t *testing.T) {
	tests := []struct {
		name    string
		dst     []byte
		src     []byte
		want    map[string]any
		wantErr bool
	}{
		{
			name: "both nil",
			dst:  nil,
			src:  nil,
			want: map[string]any{},
		},
		{
			name: "dst nil src has data",
			dst:  nil,
			src:  []byte(`{"a":1}`),
			want: map[string]any{"a": float64(1)},
		},
		{
			name: "src nil dst has data",
			dst:  []byte(`{"a":1}`),
			src:  nil,
			want: map[string]any{"a": float64(1)},
		},
		{
			name: "no overlap",
			dst:  []byte(`{"a":1}`),
			src:  []byte(`{"b":2}`),
			want: map[string]any{"a": float64(1), "b": float64(2)},
		},
		{
			name: "src overwrites dst on conflict",
			dst:  []byte(`{"a":1,"b":2}`),
			src:  []byte(`{"b":99,"c":3}`),
			want: map[string]any{"a": float64(1), "b": float64(99), "c": float64(3)},
		},
		{
			name: "empty objects",
			dst:  []byte(`{}`),
			src:  []byte(`{}`),
			want: map[string]any{},
		},
		{
			name:    "invalid dst",
			dst:     []byte(`not-json`),
			src:     []byte(`{"a":1}`),
			wantErr: true,
		},
		{
			name:    "invalid src",
			dst:     []byte(`{"a":1}`),
			src:     []byte(`not-json`),
			wantErr: true,
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got, err := MergeJSONB(tc.dst, tc.src)
			if tc.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			var gotMap map[string]any
			if err := json.Unmarshal(got, &gotMap); err != nil {
				t.Fatalf("output is not valid JSON: %v", err)
			}

			if len(gotMap) != len(tc.want) {
				t.Fatalf("got %d keys, want %d: %v", len(gotMap), len(tc.want), gotMap)
			}
			for k, wantVal := range tc.want {
				gotVal, ok := gotMap[k]
				if !ok {
					t.Errorf("missing key %q", k)
					continue
				}
				if fmt.Sprintf("%v", gotVal) != fmt.Sprintf("%v", wantVal) {
					t.Errorf("key %q: got %v, want %v", k, gotVal, wantVal)
				}
			}
		})
	}
}

func TestDatasetID(t *testing.T) {
	got := datasetID("123456", "ACADEMICS", "enrollment")
	want := "123456:ACADEMICS:enrollment"
	if got != want {
		t.Errorf("got %q, want %q", got, want)
	}
}

func TestAnnualDatasetID(t *testing.T) {
	got := annualDatasetID("123456", 2023, "ACADEMICS", "enrollment")
	want := "123456:2023:ACADEMICS:enrollment"
	if got != want {
		t.Errorf("got %q, want %q", got, want)
	}
}

func TestBatchQuery(t *testing.T) {
	q := BatchQuery{SQL: "SELECT $1", Args: []any{42}}
	if q.SQL == "" {
		t.Error("SQL should not be empty")
	}
	if len(q.Args) != 1 {
		t.Errorf("expected 1 arg, got %d", len(q.Args))
	}
}

