	// Insert two dataset rows in a single batch.
	const insertSQL = `
		INSERT INTO search_base.dataset (id, unit_id, theme, datakey, data, created, updated, version)
		VALUES ($1, $2, $3, $4, $5, now(), now(), 1)
		ON CONFLICT (id) DO NOTHING`

	queries := []BatchQuery{
		{SQL: insertSQL, Args: []any{
			datasetID(testUnitID, "COST", "tuition"), testUnitID, "COST", "tuition", []byte(`{"in_state":10000}`),
		}},
		{SQL: insertSQL, Args: []any{
			datasetID(testUnitID, "COST", "fees"), testUnitID, "COST", "fees", []byte(`{"amount":500}`),
		}},
	}

	if err := BatchExec(ctx, pool, queries); err != nil {
		t.Fatalf("BatchExec: %v", err)
	}

	var count int
	if err := pool.QueryRow(ctx,
		"SELECT COUNT(*) FROM search_base.dataset WHERE unit_id = $1", testUnitID,
	).Scan(&count); err != nil {
		t.Fatalf("count query: %v", err)
	}
	if count != 2 {
		t.Errorf("expected 2 rows, got %d", count)
	}
}

func TestIntegrationRefreshMaterializedViews(t *testing.T) {
	dbURL := os.Getenv("DATABASE_URL")
	if testing.Short() || dbURL == "" {
		t.Skip("skipping integration test")
	}
	ctx := context.Background()
	pool, err := Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("Connect: %v", err)
	}
	defer pool.Close()

	if err := RefreshMaterializedViews(ctx, pool); err != nil {
		t.Fatalf("RefreshMaterializedViews: %v", err)
	}
}

