package dbutil

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

// BatchQuery is a parameterized SQL statement with its arguments.
type BatchQuery struct {
	SQL  string
	Args []any
}

// BatchExec sends all queries as a single pgx batch, executing them within one
// round-trip. Returns the first error encountered across all results.
func BatchExec(ctx context.Context, pool *pgxpool.Pool, queries []BatchQuery) error {
	if len(queries) == 0 {
		return nil
	}

	batch := &pgx.Batch{}
	for _, q := range queries {
		batch.Queue(q.SQL, q.Args...)
	}

	results := pool.SendBatch(ctx, batch)
	defer results.Close()

	for i := range queries {
		if _, err := results.Exec(); err != nil {
			return fmt.Errorf("dbutil: batch exec query %d: %w", i, err)
		}
	}
	return nil
}

// CopyFrom bulk-inserts rows into the given table using PostgreSQL's COPY
// protocol. Returns the number of rows inserted.
func CopyFrom(ctx context.Context, pool *pgxpool.Pool, tableName pgx.Identifier, columns []string, rows [][]any) (int64, error) {
	rowSrc := pgx.CopyFromRows(rows)
	n, err := pool.CopyFrom(ctx, tableName, columns, rowSrc)
	if err != nil {
		return 0, fmt.Errorf("dbutil: copy from %s: %w", tableName.Sanitize(), err)
	}
	return n, nil
}

