				{Value: "22", Label: "Suburb: Midsize"},
				{Value: "23", Label: "Suburb: Small"},
				{Value: "31", Label: "Town: Fringe"},
				{Value: "32", Label: "Town: Distant"},
				{Value: "33", Label: "Town: Remote"},
				{Value: "41", Label: "Rural: Fringe"},
				{Value: "42", Label: "Rural: Distant"},
				{Value: "43", Label: "Rural: Remote"},
			},
		},

		&SingleEnumField{
			baseField: baseField{
				name: "region", label: "Region",
				description:   "NCES geographic region",
				kind:          KindSingleEnum,
				theme:         ThemeLocation,
				source:        FieldSource{Kind: SourceJSONBPath, JSONBPath: []string{"nces", "region_id"}, ValueType: JSONBText},
				visibility:    VisibilityVisible,
				searchability: SearchabilitySearchable,
				exportable:    boolPtr(true),
