// SetAdmissionsSQL is the SQL used by SetAdmissions. Exported for testing.
const SetAdmissionsSQL = `
UPDATE search_base.institution
SET admissions = $2, updated = now(), version = version + 1
WHERE unit_id = $1`

// SetAdmissions replaces the admissions JSONB column for a single institution.
// This uses replace (not merge) semantics so that dropped platforms disappear.
func SetAdmissions(ctx context.Context, pool *pgxpool.Pool, unitID string, admissionsJSON []byte) error {
	_, err := pool.Exec(ctx, SetAdmissionsSQL, unitID, admissionsJSON)
	if err != nil {
		return fmt.Errorf("dbutil: set admissions %s: %w", unitID, err)
	}
	return nil
}

// BulkSetAdmissions replaces the admissions JSONB column for multiple
// institutions in a single batch round-trip.
func BulkSetAdmissions(ctx context.Context, pool *pgxpool.Pool, admissions map[string][]byte) error {
	if len(admissions) == 0 {
		return nil
	}
	queries := make([]BatchQuery, 0, len(admissions))
	for unitID, data := range admissions {
		queries = append(queries, BatchQuery{SQL: SetAdmissionsSQL, Args: []any{unitID, data}})
	}
	return BatchExec(ctx, pool, queries)
}

