package platform

import "context"

// Browser is satisfied by scraper.Browser (defined in the scraper package).
type Browser interface {
	Navigate(ctx context.Context, url string) error
	EvalStrings(ctx context.Context, jsExpr string) ([]string, error)
}

// Extractor scrapes a college application platform's member list.
type Extractor interface {
	Key() string   // enum value stored in JSONB (e.g. "Common", "CBCA")
	Label() string // human-readable label (e.g. "Common App")
	Extract(ctx context.Context, browser Browser) ([]string, error)
}

// Platform key constants.
const (
	KeyCommon        = "Common"
	KeyCoalition     = "Coalition"
	KeyCBCA          = "CBCA"
	KeyQuestBridge   = "QuestBridge"
	KeyApplyTexas    = "ApplyTexas"
	KeyApplySUNY     = "ApplySUNY"
	KeyUCApplication = "UCApplication"
	KeyCalStateApply = "CalStateApply"
	KeyUWSystem      = "UWSystem"
	KeyApplyIdaho    = "ApplyIdaho"
	KeyGAFutures     = "GAFutures"
	KeyCFNC          = "CFNC"
	KeyFloridaSUS    = "FloridaSUS"
)

// AllKeys returns all platform key constants.
func AllKeys() []string {
	return []string{
		KeyCommon, KeyCoalition, KeyCBCA, KeyQuestBridge,
		KeyApplyTexas, KeyApplySUNY, KeyUCApplication, KeyCalStateApply,
		KeyUWSystem, KeyApplyIdaho, KeyGAFutures, KeyCFNC, KeyFloridaSUS,
	}
}

// All returns all registered extractors. Initially empty;
// populated as each extractor implementation is added.
func All() []Extractor {
	return nil
}

package platform

import "testing"

func TestAllKeysCount(t *testing.T) {
	keys := AllKeys()
	if len(keys) != 13 {
		t.Errorf("AllKeys() returned %d keys, want 13", len(keys))
	}
}

func TestAllKeysUnique(t *testing.T) {
	seen := make(map[string]bool)
	for _, k := range AllKeys() {
		if seen[k] {
			t.Errorf("duplicate key: %s", k)
		}
		seen[k] = true
	}
}

func TestKeyConstants(t *testing.T) {
	expected := map[string]string{
		"KeyCommon":        KeyCommon,
		"KeyCoalition":     KeyCoalition,
		"KeyCBCA":          KeyCBCA,
		"KeyQuestBridge":   KeyQuestBridge,
		"KeyApplyTexas":    KeyApplyTexas,
		"KeyApplySUNY":     KeyApplySUNY,
		"KeyUCApplication": KeyUCApplication,
		"KeyCalStateApply": KeyCalStateApply,
		"KeyUWSystem":      KeyUWSystem,
		"KeyApplyIdaho":    KeyApplyIdaho,
		"KeyGAFutures":     KeyGAFutures,
		"KeyCFNC":          KeyCFNC,
		"KeyFloridaSUS":    KeyFloridaSUS,
	}
	want := map[string]string{
		"KeyCommon":        "Common",
		"KeyCoalition":     "Coalition",
		"KeyCBCA":          "CBCA",
		"KeyQuestBridge":   "QuestBridge",
		"KeyApplyTexas":    "ApplyTexas",
		"KeyApplySUNY":     "ApplySUNY",
		"KeyUCApplication": "UCApplication",
		"KeyCalStateApply": "CalStateApply",
		"KeyUWSystem":      "UWSystem",
		"KeyApplyIdaho":    "ApplyIdaho",
		"KeyGAFutures":     "GAFutures",
		"KeyCFNC":          "CFNC",
		"KeyFloridaSUS":    "FloridaSUS",
	}
	for name, got := range expected {
		if w, ok := want[name]; ok && got != w {
			t.Errorf("%s = %q, want %q", name, got, w)
		}
	}
}

func TestAllExtractorsUniqueKeys(t *testing.T) {
	extractors := All()
	seen := make(map[string]bool)
	for _, e := range extractors {
		k := e.Key()
		if seen[k] {
			t.Errorf("duplicate extractor key: %s", k)
		}
		seen[k] = true
	}
}

package scraper

import (
	"context"
	"fmt"
	"time"

	"github.com/chromedp/chromedp"
)

// Option configures a Browser.
type Option func(*browserConfig)

type browserConfig struct {
	headless  bool
	width     int
	height    int
	userAgent string
	timeout   time.Duration
}

func defaultConfig() browserConfig {
	return browserConfig{
		headless:  true,
		width:     1920,
		height:    1080,
		userAgent: "",
		timeout:   30 * time.Second,
	}
}

// WithHeadless sets whether Chrome runs headless (default true).
func WithHeadless(v bool) Option {
	return func(c *browserConfig) { c.headless = v }
}

// WithViewport sets the browser viewport size.
func WithViewport(w, h int) Option {
	return func(c *browserConfig) { c.width = w; c.height = h }
}

// WithUserAgent sets a custom user-agent string.
func WithUserAgent(ua string) Option {
	return func(c *browserConfig) { c.userAgent = ua }
}

// WithTimeout sets the default timeout for page operations.
func WithTimeout(d time.Duration) Option {
	return func(c *browserConfig) { c.timeout = d }
}

// Browser wraps a chromedp allocator for scraping web pages.
type Browser struct {
	cfg       browserConfig
	allocCtx  context.Context
	cancelAll context.CancelFunc
}

// New launches a headless Chrome instance.
func New(opts ...Option) (*Browser, error) {
	cfg := defaultConfig()
	for _, o := range opts {
		o(&cfg)
	}

	allocOpts := chromedp.DefaultExecAllocatorOptions[:]
	if !cfg.headless {
		// Remove the headless flags by filtering.
		allocOpts = append(allocOpts,
			chromedp.Flag("headless", false),
		)
	}
	allocOpts = append(allocOpts,
		chromedp.WindowSize(cfg.width, cfg.height),
	)
	if cfg.userAgent != "" {
		allocOpts = append(allocOpts, chromedp.UserAgent(cfg.userAgent))
	}

	allocCtx, cancelAlloc := chromedp.NewExecAllocator(context.Background(), allocOpts...)
	// Create a browser context so all tabs share the same browser.
	browserCtx, cancelBrowser := chromedp.NewContext(allocCtx)

