// Option configures a Browser.
type Option func(*browserConfig)

type browserConfig struct {
	headless  bool
	width     int
	height    int
	userAgent string
	timeout   time.Duration
}

func defaultConfig() browserConfig {
	return browserConfig{
		headless:  true,
		width:     1920,
		height:    1080,
		userAgent: "",
		timeout:   30 * time.Second,
	}
}

// WithHeadless sets whether Chrome runs headless (default true).
func WithHeadless(v bool) Option {
	return func(c *browserConfig) { c.headless = v }
}

// WithViewport sets the browser viewport size.
func WithViewport(w, h int) Option {
	return func(c *browserConfig) { c.width = w; c.height = h }
}

// WithUserAgent sets a custom user-agent string.
func WithUserAgent(ua string) Option {
	return func(c *browserConfig) { c.userAgent = ua }
}

// WithTimeout sets the default timeout for page operations.
func WithTimeout(d time.Duration) Option {
	return func(c *browserConfig) { c.timeout = d }
}

// Browser wraps a chromedp allocator for scraping web pages.
type Browser struct {
	cfg       browserConfig
	allocCtx  context.Context
	cancelAll context.CancelFunc
}

// New launches a headless Chrome instance.
func New(opts ...Option) (*Browser, error) {
	cfg := defaultConfig()
	for _, o := range opts {
		o(&cfg)
	}

	allocOpts := chromedp.DefaultExecAllocatorOptions[:]
	if !cfg.headless {
		// Remove the headless flags by filtering.
		allocOpts = append(allocOpts,
			chromedp.Flag("headless", false),
		)
	}
	allocOpts = append(allocOpts,
		chromedp.WindowSize(cfg.width, cfg.height),
	)
	if cfg.userAgent != "" {
		allocOpts = append(allocOpts, chromedp.UserAgent(cfg.userAgent))
	}

	allocCtx, cancelAlloc := chromedp.NewExecAllocator(context.Background(), allocOpts...)
	// Create a browser context so all tabs share the same browser.
	browserCtx, cancelBrowser := chromedp.NewContext(allocCtx)

	// Run an empty action to actually start the browser.
	if err := chromedp.Run(browserCtx); err != nil {
		cancelBrowser()
		cancelAlloc()
		return nil, fmt.Errorf("scraper: start browser: %w", err)
	}

	return &Browser{
		cfg:      cfg,
		allocCtx: browserCtx,
		cancelAll: func() {
			cancelBrowser()
			cancelAlloc()
		},
	}, nil
}

