func TestSetAdmissionsSQL(t *testing.T) {
	sql := SetAdmissionsSQL
	if sql == "" {
		t.Fatal("SetAdmissionsSQL should not be empty")
	}
	// Verify it's an UPDATE (not INSERT ... ON CONFLICT).
	if !contains(sql, "UPDATE search_base.institution") {
		t.Error("expected UPDATE search_base.institution")
	}
	if !contains(sql, "SET admissions = $2") {
		t.Error("expected SET admissions = $2")
	}
	if !contains(sql, "version = version + 1") {
		t.Error("expected version increment")
	}
	if !contains(sql, "WHERE unit_id = $1") {
		t.Error("expected WHERE unit_id = $1")
	}
	// Must NOT use COALESCE merge — replace semantics.
	if contains(sql, "COALESCE") {
		t.Error("SetAdmissions should NOT use COALESCE — replace semantics")
