func TestIntegrationUpsertInstitution(t *testing.T) {
	dbURL := os.Getenv("DATABASE_URL")
	if testing.Short() || dbURL == "" {
		t.Skip("skipping integration test")
	}
	ctx := context.Background()
	pool, err := Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("Connect: %v", err)
	}
	defer pool.Close()

	const testUnitID = "TEST_DBUTIL_01"
	t.Cleanup(func() {
		_, _ = pool.Exec(ctx, "DELETE FROM search_base.institution WHERE unit_id = $1", testUnitID)
	})

	inst := &Institution{
		UnitID: testUnitID,
		OPE6ID: "999999",
		OPE8ID: "99999900",
		Name:   "Test University",
		City:   "Testville",
		State:  "TX",
		NCES:   []byte(`{"control":1}`),
	}

	if err := UpsertInstitution(ctx, pool, inst); err != nil {
		t.Fatalf("first upsert: %v", err)
	}

	// Verify row exists.
	var name string
	var version int
	err = pool.QueryRow(ctx,
		"SELECT institution_name, version FROM search_base.institution WHERE unit_id = $1",
		testUnitID,
	).Scan(&name, &version)
	if err != nil {
		t.Fatalf("QueryRow after insert: %v", err)
	}
	if name != "Test University" {
		t.Errorf("name = %q, want %q", name, "Test University")
	}
	if version != 1 {
		t.Errorf("version = %d, want 1", version)
	}

	// Re-upsert — version should increment.
	inst.NCES = []byte(`{"control":1,"size":5000}`)
	if err := UpsertInstitution(ctx, pool, inst); err != nil {
		t.Fatalf("second upsert: %v", err)
	}

	err = pool.QueryRow(ctx,
		"SELECT version FROM search_base.institution WHERE unit_id = $1",
		testUnitID,
	).Scan(&version)
	if err != nil {
		t.Fatalf("QueryRow after re-upsert: %v", err)
	}
	if version != 2 {
		t.Errorf("version after re-upsert = %d, want 2", version)
	}
}

