package search

// DataSource describes the origin of one or more search fields.
type DataSource struct {
	// ID is a short, unique, kebab-case identifier (e.g. "nces-ipeds").
	ID string
	// Name is the full human-readable name of the data source.
	Name string
	// ShortName is a compact label suitable for UI badges or tooltips.
	ShortName string
	// Dataset is the top-level JSONB key or logical grouping that ties
	// this source to columns in the search_base.dataset_merged view.
	Dataset string
	// URL points to the canonical homepage or documentation for the source.
	URL string
	// Description is a one-sentence summary of what the source provides.
	Description string
}

// ── Source catalog ───────────────────────────────────────────────────────────

var (
	SourceNCESIPEDS = DataSource{
		ID:          "nces-ipeds",
		Name:        "National Center for Education Statistics (IPEDS)",
		ShortName:   "NCES",
		Dataset:     "nces",
		URL:         "https://nces.ed.gov/ipeds/",
		Description: "Federal survey data covering academics, cost, outcomes, enrollment, and demographics.",
	}

	SourceUSNewsNational = DataSource{
		ID:          "us-news-national",
